   640→  /**
   641→   * Update train fitness status with validation.
   642→   *
   643→   * Valid transitions:
   644→   * - FIT -> RESTRICTED, GROUNDED
   645→   * - RESTRICTED -> FIT, GROUNDED
   646→   * - GROUNDED -> RESTRICTED, FIT
   647→   *
   648→   * Note: Transitions from GROUNDED to FIT should typically go through RESTRICTED
   649→   * for inspection, but this is not enforced (operational flexibility).
   650→   */
   651→  async updateFitnessStatus(request: FitnessStatusChangeRequest): Promise<Train> {
   652→    return this.inTransaction('updateFitnessStatus', async (tx, span) => {
   653→      const { trainId, newStatus, notes, changedBy } = request;
   654→
   655→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   656→      span.setAttribute('fitness.newStatus', newStatus);
   657→
   658→      const train = await tx.query.trains.findFirst({
   659→        where: eq(trains.id, trainId),
   660→      });
   661→
   662→      if (!train) {
   663→        throw new TrainNotFoundError(trainId);
   664→      }
   665→
   666→      const oldStatus = train.fitnessStatus;
   667→      span.setAttribute('fitness.oldStatus', oldStatus ?? 'null');
   668→
   669→      // Log transition
   670→      this.log.info(
   671→        {
   672→          trainId,
   673→          trainNumber: train.trainNumber,
   674→          oldStatus,
   675→          newStatus,
   676→          changedBy,
   677→        },
   678→        `Train fitness status change: ${oldStatus} -> ${newStatus}`
   679→      );
   680→
   681→      // Update with notes
   682→      const [result] = await tx
   683→        .update(trains)
   684→        .set({
   685→          fitnessStatus: newStatus,
   686→          fitnessNotes: notes ?? train.fitnessNotes,
   687→          updatedAt: new Date(),
   688→        })
   689→        .where(eq(trains.id, trainId))
   690→        .returning();
   691→
   692→      this.recordEvent('train.fitness_changed', {
   693→        [MmsAttributes.TRAIN_ID]: trainId,
   694→        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
   695→        'fitness.old': oldStatus ?? 'unknown',
   696→        'fitness.new': newStatus,
   697→      }, span);
   698→
   699→      return result;
   700→    });
   701→  }
