   841→  /**
   842→   * Calculate and update fleet mileage targets for balancing.
   843→   * Target = fleet average mileage, variance = current - target
   844→   */
   845→  async recalculateFleetTargets(fleetId: string): Promise<void> {
   846→    return this.inTransaction('recalculateFleetTargets', async (tx, span) => {
   847→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
   848→
   849→      // Get average mileage for the fleet
   850→      const [{ avgMileage }] = await tx
   851→        .select({ avgMileage: avg(trains.currentMileageKm) })
   852→        .from(trains)
   853→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
   854→
   855→      const targetMileage = Math.round(Number(avgMileage) || 0);
   856→      span.setAttribute('mileage.target', targetMileage);
   857→
   858→      // Update all trains in fleet with new target
   859→      await tx
   860→        .update(trains)
   861→        .set({
   862→          targetMileageKm: targetMileage,
   863→          updatedAt: new Date(),
   864→        })
   865→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
   866→
   867→      this.log.info(
   868→        { fleetId, targetMileage },
   869→        'Fleet mileage targets recalculated'
   870→      );
   871→    });
   872→  }
