  1139→  /**
  1140→   * Get comprehensive statistics for a fleet
  1141→   */
  1142→  async getFleetStatistics(fleetId: string): Promise<FleetStatistics> {
  1143→    return this.traced('getFleetStatistics', async (span) => {
  1144→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
  1145→
  1146→      // Verify fleet exists
  1147→      const fleet = await this.db.query.fleets.findFirst({
  1148→        where: eq(fleets.id, fleetId),
  1149→      });
  1150→
  1151→      if (!fleet) {
  1152→        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
  1153→          entityType: 'fleet',
  1154→          entityId: fleetId,
  1155→        });
  1156→      }
  1157→
  1158→      // Get all stats in one query
  1159→      const statsQuery = await this.db
  1160→        .select({
  1161→          totalTrains: count(),
  1162→          totalMileageKm: sum(trains.currentMileageKm),
  1163→          averageMileageKm: avg(trains.currentMileageKm),
  1164→          minMileageKm: sql<number>`MIN(${trains.currentMileageKm})`,
  1165→          maxMileageKm: sql<number>`MAX(${trains.currentMileageKm})`,
  1166→          stdDevMileageKm: sql<number>`STDDEV(${trains.currentMileageKm})`,
  1167→        })
  1168→        .from(trains)
  1169→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
  1170→
  1171→      const stats = statsQuery[0];
  1172→
  1173→      // Get counts by fitness status
  1174→      const fitnessCounts = await this.db
  1175→        .select({
  1176→          status: trains.fitnessStatus,
  1177→          count: count(),
  1178→        })
  1179→        .from(trains)
  1180→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)))
  1181→        .groupBy(trains.fitnessStatus);
  1182→
  1183→      const statusMap = new Map(fitnessCounts.map((fc) => [fc.status, fc.count]));
  1184→
  1185→      const result: FleetStatistics = {
  1186→        fleetId,
  1187→        fleetCode: fleet.code,
  1188→        totalTrains: Number(stats.totalTrains) || 0,
  1189→        activeTrains: Number(stats.totalTrains) || 0,
  1190→        fitTrains: statusMap.get('FIT') || 0,
  1191→        restrictedTrains: statusMap.get('RESTRICTED') || 0,
  1192→        groundedTrains: statusMap.get('GROUNDED') || 0,
  1193→        totalMileageKm: Number(stats.totalMileageKm) || 0,
  1194→        averageMileageKm: Math.round(Number(stats.averageMileageKm) || 0),
