/**
 * MMS Fleet Service
 *
 * Core domain service for fleet asset management.
 * Provides CRUD operations for depots, fleets, trains, routes, and tracks.
 * Manages train lifecycle states and mileage tracking.
 *
 * Business rules:
 * - Train fitness transitions: FIT <-> RESTRICTED <-> GROUNDED
 * - Mileage accumulation is additive (never decreases except for corrections)
 * - Fleet mileage balancing: target = fleet average, variance = current - target
 * - Active entities can be deactivated but not deleted (audit compliance)
 *
 * @see specs/003-database-schema.md Section 3.2 (Core Fleet Domain)
 */

import { eq, and, inArray, sql, desc, asc, count, avg, sum, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  depots,
  fleets,
  trains,
  routes,
  tracks,
  type Depot,
  type NewDepot,
  type Fleet,
  type NewFleet,
  type Train,
  type NewTrain,
  type Route,
  type NewRoute,
  type Track,
  type NewTrack,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  ValidationError,
  DuplicateError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Valid fitness status transitions */
type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';

/** Query filters for listing trains */
export interface TrainListFilters {
  fleetId?: string;
  depotId?: string;
  fitnessStatus?: FitnessStatus | FitnessStatus[];
  active?: boolean;
  trainNumbers?: string[];
}

/** Query filters for listing fleets */
export interface FleetListFilters {
  baseDepotId?: string;
  manufacturer?: string;
  active?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result */
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Fleet statistics */
export interface FleetStatistics {
  fleetId: string;
  fleetCode: string;
  totalTrains: number;
  activeTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  totalMileageKm: number;
  averageMileageKm: number;
  minMileageKm: number;
  maxMileageKm: number;
  mileageStdDevKm: number;
}

/** Train with fleet details */
export interface TrainWithFleet extends Train {
  fleet: Fleet | null;
  currentDepot: Depot | null;
  homeDepot: Depot | null;
}

/** Fitness status change request */
export interface FitnessStatusChangeRequest {
  trainId: string;
  newStatus: FitnessStatus;
  notes?: string;
  changedBy?: string;
}

/** Mileage update request */
export interface MileageUpdateRequest {
  trainId: string;
  newMileageKm: number;
  source?: string;
}

// =============================================================================
// Fleet Service
// =============================================================================

export class FleetService extends BaseService {
  constructor() {
    super({ name: 'fleet-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Depot Operations
  // ===========================================================================

  async getDepotById(id: string): Promise<Depot> {
    return this.traced('getDepotById', async (span) => {
      span.setAttribute(MmsAttributes.DEPOT_ID, id);

      const result = await this.db.query.depots.findFirst({
        where: eq(depots.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Depot not found: ${id}`, {
          entityType: 'depot',
          entityId: id,
        });
      }

      return result;
    });
  }

  async getDepotByCode(code: string): Promise<Depot> {
    return this.traced('getDepotByCode', async (span) => {
      span.setAttribute('depot.code', code);

      const result = await this.db.query.depots.findFirst({
        where: eq(depots.code, code),
      });

      if (!result) {
        throw new NotFoundError(`Depot not found with code: ${code}`, {
          entityType: 'depot',
          entityId: code,
        });
      }

      return result;
    });
  }

  async listDepots(options?: { active?: boolean }): Promise<Depot[]> {
    return this.traced('listDepots', async (span) => {
      const conditions: SQL<unknown>[] = [];
      if (options?.active !== undefined) {
        conditions.push(eq(depots.active, options.active));
      }

      const result = await this.db.query.depots.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(depots.code),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createDepot(data: NewDepot): Promise<Depot> {
    return this.inTransaction('createDepot', async (tx, span) => {
      span.setAttribute('depot.code', data.code);

      // Check for duplicate code
      const existing = await tx.query.depots.findFirst({
        where: eq(depots.code, data.code),
      });

      if (existing) {
        throw new DuplicateError(`Depot with code ${data.code} already exists`, {
          field: 'code',
          value: data.code,
        });
      }

      const [result] = await tx.insert(depots).values(data).returning();
      span.setAttribute(MmsAttributes.DEPOT_ID, result.id);

      this.log.info({ depotId: result.id, code: data.code }, 'Depot created');
      return result;
    });
  }

  async updateDepot(id: string, data: Partial<NewDepot>): Promise<Depot> {
    return this.inTransaction('updateDepot', async (tx, span) => {
      span.setAttribute(MmsAttributes.DEPOT_ID, id);

      const existing = await tx.query.depots.findFirst({
        where: eq(depots.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Depot not found: ${id}`, {
          entityType: 'depot',
          entityId: id,
        });
      }

      // Check for duplicate code if changing
      if (data.code && data.code !== existing.code) {
        const duplicate = await tx.query.depots.findFirst({
          where: eq(depots.code, data.code),
        });
        if (duplicate) {
          throw new DuplicateError(`Depot with code ${data.code} already exists`, {
            field: 'code',
            value: data.code,
          });
        }
      }

      const [result] = await tx
        .update(depots)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(depots.id, id))
        .returning();

      return result;
    });
  }

  async deactivateDepot(id: string): Promise<Depot> {
    return this.updateDepot(id, { active: false });
  }

  // ===========================================================================
  // Fleet Operations
  // ===========================================================================

  async getFleetById(id: string): Promise<Fleet> {
    return this.traced('getFleetById', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, id);

      const result = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Fleet not found: ${id}`, {
          entityType: 'fleet',
          entityId: id,
        });
      }

      return result;
    });
  }

  async getFleetByCode(code: string): Promise<Fleet> {
    return this.traced('getFleetByCode', async (span) => {
      span.setAttribute('fleet.code', code);

      const result = await this.db.query.fleets.findFirst({
        where: eq(fleets.code, code),
      });

      if (!result) {
        throw new NotFoundError(`Fleet not found with code: ${code}`, {
          entityType: 'fleet',
          entityId: code,
        });
      }

      return result;
    });
  }

  async listFleets(filters?: FleetListFilters): Promise<Fleet[]> {
    return this.traced('listFleets', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.baseDepotId) {
        conditions.push(eq(fleets.baseDepotId, filters.baseDepotId));
      }
      if (filters?.manufacturer) {
        conditions.push(eq(fleets.manufacturer, filters.manufacturer));
      }
      if (filters?.active !== undefined) {
        conditions.push(eq(fleets.active, filters.active));
      }

      const result = await this.db.query.fleets.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(fleets.code),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createFleet(data: NewFleet): Promise<Fleet> {
    return this.inTransaction('createFleet', async (tx, span) => {
      span.setAttribute('fleet.code', data.code);

      // Validate base depot exists if provided
      if (data.baseDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.baseDepotId),
        });
        if (!depot) {
          throw new ValidationError('Base depot not found', {
            field: 'baseDepotId',
            context: { depotId: data.baseDepotId },
          });
        }
      }

      // Check for duplicate code
      const existing = await tx.query.fleets.findFirst({
        where: eq(fleets.code, data.code),
      });

      if (existing) {
        throw new DuplicateError(`Fleet with code ${data.code} already exists`, {
          field: 'code',
          value: data.code,
        });
      }

      const [result] = await tx.insert(fleets).values(data).returning();
      span.setAttribute(MmsAttributes.FLEET_ID, result.id);

      this.log.info({ fleetId: result.id, code: data.code }, 'Fleet created');
      return result;
    });
  }

  async updateFleet(id: string, data: Partial<NewFleet>): Promise<Fleet> {
    return this.inTransaction('updateFleet', async (tx, span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, id);

      const existing = await tx.query.fleets.findFirst({
        where: eq(fleets.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Fleet not found: ${id}`, {
          entityType: 'fleet',
          entityId: id,
        });
      }

      // Check for duplicate code if changing
      if (data.code && data.code !== existing.code) {
        const duplicate = await tx.query.fleets.findFirst({
          where: eq(fleets.code, data.code),
        });
        if (duplicate) {
          throw new DuplicateError(`Fleet with code ${data.code} already exists`, {
            field: 'code',
            value: data.code,
          });
        }
      }

      const [result] = await tx
        .update(fleets)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(fleets.id, id))
        .returning();

      return result;
    });
  }

  async deactivateFleet(id: string): Promise<Fleet> {
    return this.updateFleet(id, { active: false });
  }

  // ===========================================================================
  // Train Operations
  // ===========================================================================

  async getTrainById(id: string): Promise<Train> {
    return this.traced('getTrainById', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.id, id),
      });

      if (!result) {
        throw new TrainNotFoundError(id);
      }

      return result;
    });
  }

  async getTrainByNumber(trainNumber: string): Promise<Train> {
    return this.traced('getTrainByNumber', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_NUMBER, trainNumber);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.trainNumber, trainNumber),
      });

      if (!result) {
        throw new NotFoundError(`Train not found with number: ${trainNumber}`, {
          entityType: 'train',
          entityId: trainNumber,
        });
      }

      return result;
    });
  }

  async getTrainWithDetails(id: string): Promise<TrainWithFleet> {
    return this.traced('getTrainWithDetails', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const result = await this.db.query.trains.findFirst({
        where: eq(trains.id, id),
        with: {
          fleet: true,
          currentDepot: true,
          homeDepot: true,
        },
      });

      if (!result) {
        throw new TrainNotFoundError(id);
      }

      return result as TrainWithFleet;
    });
  }

  async listTrains(
    filters?: TrainListFilters,
    pagination?: PaginationOptions
  ): Promise<PaginatedResult<Train>> {
    return this.traced('listTrains', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.fleetId) {
        conditions.push(eq(trains.fleetId, filters.fleetId));
      }
      if (filters?.depotId) {
        conditions.push(eq(trains.currentDepotId, filters.depotId));
      }
      if (filters?.fitnessStatus) {
        if (Array.isArray(filters.fitnessStatus)) {
          conditions.push(inArray(trains.fitnessStatus, filters.fitnessStatus));
        } else {
          conditions.push(eq(trains.fitnessStatus, filters.fitnessStatus));
        }
      }
      if (filters?.active !== undefined) {
        conditions.push(eq(trains.active, filters.active));
      }
      if (filters?.trainNumbers && filters.trainNumbers.length > 0) {
        conditions.push(inArray(trains.trainNumber, filters.trainNumbers));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(trains)
        .where(whereClause);

      // Apply pagination
      const page = pagination?.page ?? 1;
      const pageSize = Math.min(pagination?.pageSize ?? 50, 500);
      const offset = (page - 1) * pageSize;

      // Determine sort order
      const sortDirection = pagination?.sortOrder === 'desc' ? desc : asc;
      const getOrderBy = () => {
        switch (pagination?.sortBy) {
          case 'mileage':
            return sortDirection(trains.currentMileageKm);
          case 'fitnessStatus':
            return sortDirection(trains.fitnessStatus);
          default:
            return sortDirection(trains.trainNumber);
        }
      };

      const data = await this.db.query.trains.findMany({
        where: whereClause,
        orderBy: getOrderBy(),
        limit: pageSize,
        offset,
      });

      span.setAttribute('result.count', data.length);
      span.setAttribute('result.total', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

  async createTrain(data: NewTrain): Promise<Train> {
    return this.inTransaction('createTrain', async (tx, span) => {
      span.setAttribute(MmsAttributes.TRAIN_NUMBER, data.trainNumber);

      // Validate fleet exists
      const fleet = await tx.query.fleets.findFirst({
        where: eq(fleets.id, data.fleetId),
      });
      if (!fleet) {
        throw new ValidationError('Fleet not found', {
          field: 'fleetId',
          context: { fleetId: data.fleetId },
        });
      }

      // Validate depots if provided
      if (data.currentDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.currentDepotId),
        });
        if (!depot) {
          throw new ValidationError('Current depot not found', {
            field: 'currentDepotId',
            context: { depotId: data.currentDepotId },
          });
        }
      }

      if (data.homeDepotId) {
        const depot = await tx.query.depots.findFirst({
          where: eq(depots.id, data.homeDepotId),
        });
        if (!depot) {
          throw new ValidationError('Home depot not found', {
            field: 'homeDepotId',
            context: { depotId: data.homeDepotId },
          });
        }
      }

      // Check for duplicate train number
      const existing = await tx.query.trains.findFirst({
        where: eq(trains.trainNumber, data.trainNumber),
      });

      if (existing) {
        throw new DuplicateError(`Train with number ${data.trainNumber} already exists`, {
          field: 'trainNumber',
          value: data.trainNumber,
        });
      }

      const [result] = await tx.insert(trains).values(data).returning();
      span.setAttribute(MmsAttributes.TRAIN_ID, result.id);

      this.log.info(
        { trainId: result.id, trainNumber: data.trainNumber, fleetId: data.fleetId },
        'Train created'
      );
      return result;
    });
  }

  async updateTrain(id: string, data: Partial<NewTrain>): Promise<Train> {
    return this.inTransaction('updateTrain', async (tx, span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, id);

      const existing = await tx.query.trains.findFirst({
        where: eq(trains.id, id),
      });

      if (!existing) {
        throw new TrainNotFoundError(id);
      }

      // Check for duplicate train number if changing
      if (data.trainNumber && data.trainNumber !== existing.trainNumber) {
        const duplicate = await tx.query.trains.findFirst({
          where: eq(trains.trainNumber, data.trainNumber),
        });
        if (duplicate) {
          throw new DuplicateError(`Train with number ${data.trainNumber} already exists`, {
            field: 'trainNumber',
            value: data.trainNumber,
          });
        }
      }

      const [result] = await tx
        .update(trains)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(trains.id, id))
        .returning();

      return result;
    });
  }

  async deactivateTrain(id: string): Promise<Train> {
    return this.updateTrain(id, { active: false });
  }

  // ===========================================================================
  // Train Fitness Status Management
  // ===========================================================================

  /**
   * Update train fitness status with validation.
   *
   * Valid transitions:
   * - FIT -> RESTRICTED, GROUNDED
   * - RESTRICTED -> FIT, GROUNDED
   * - GROUNDED -> RESTRICTED, FIT
   *
   * Note: Transitions from GROUNDED to FIT should typically go through RESTRICTED
   * for inspection, but this is not enforced (operational flexibility).
   */
  async updateFitnessStatus(request: FitnessStatusChangeRequest): Promise<Train> {
    return this.inTransaction('updateFitnessStatus', async (tx, span) => {
      const { trainId, newStatus, notes, changedBy } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('fitness.newStatus', newStatus);

      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const oldStatus = train.fitnessStatus;
      span.setAttribute('fitness.oldStatus', oldStatus ?? 'null');

      // Log transition
      this.log.info(
        {
          trainId,
          trainNumber: train.trainNumber,
          oldStatus,
          newStatus,
          changedBy,
        },
        `Train fitness status change: ${oldStatus} -> ${newStatus}`
      );

      // Update with notes
      const [result] = await tx
        .update(trains)
        .set({
          fitnessStatus: newStatus,
          fitnessNotes: notes ?? train.fitnessNotes,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, trainId))
        .returning();

      this.recordEvent('train.fitness_changed', {
        [MmsAttributes.TRAIN_ID]: trainId,
        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
        'fitness.old': oldStatus ?? 'unknown',
        'fitness.new': newStatus,
      }, span);

      return result;
    });
  }

  /**
   * Get trains by fitness status with optional fleet filter
   */
  async getTrainsByFitnessStatus(
    status: FitnessStatus,
    fleetId?: string
  ): Promise<Train[]> {
    return this.traced('getTrainsByFitnessStatus', async (span) => {
      span.setAttribute('fitness.status', status);
      if (fleetId) {
        span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      }

      const conditions = [
        eq(trains.fitnessStatus, status),
        eq(trains.active, true),
      ];

      if (fleetId) {
        conditions.push(eq(trains.fleetId, fleetId));
      }

      const result = await this.db.query.trains.findMany({
        where: and(...conditions),
        orderBy: asc(trains.trainNumber),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Get count of available (FIT) trains for a fleet
   */
  async getAvailableTrainCount(fleetId: string): Promise<number> {
    return this.traced('getAvailableTrainCount', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      const [{ fitCount }] = await this.db
        .select({ fitCount: count() })
        .from(trains)
        .where(
          and(
            eq(trains.fleetId, fleetId),
            eq(trains.fitnessStatus, 'FIT'),
            eq(trains.active, true)
          )
        );

      span.setAttribute('result.fitCount', fitCount);
      return fitCount;
    });
  }

  // ===========================================================================
  // Mileage Operations
  // ===========================================================================

  /**
   * Update train mileage (typically called by ingestion service)
   *
   * Validates:
   * - New mileage must be >= current (no rollback unless meter event)
   * - Maximum daily increase: 2000 km (configurable)
   */
  async updateMileage(request: MileageUpdateRequest): Promise<Train> {
    return this.inTransaction('updateMileage', async (tx, span) => {
      const { trainId, newMileageKm, source } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute(MmsAttributes.MILEAGE_KM, newMileageKm);

      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const oldMileage = train.currentMileageKm;
      const delta = newMileageKm - oldMileage;

      span.setAttribute('mileage.old', oldMileage);
      span.setAttribute('mileage.delta', delta);

      // Validate mileage increase
      if (delta < 0) {
        throw new BusinessRuleError(
          `Mileage cannot decrease (${oldMileage} -> ${newMileageKm}). Use meter event for corrections.`,
          {
            rule: 'mileage_no_decrease',
            context: { trainId, oldMileage, newMileageKm },
          }
        );
      }

      // Warn on large delta (>2000km in single update)
      if (delta > 2000) {
        this.log.warn(
          {
            trainId,
            trainNumber: train.trainNumber,
            oldMileage,
            newMileageKm,
            delta,
            source,
          },
          'Large mileage delta detected - possible anomaly'
        );
      }

      const [result] = await tx
        .update(trains)
        .set({
          currentMileageKm: newMileageKm,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, trainId))
        .returning();

      this.log.info(
        {
          trainId,
          trainNumber: train.trainNumber,
          oldMileage,
          newMileageKm,
          delta,
          source,
        },
        `Train mileage updated: ${oldMileage} -> ${newMileageKm} (+${delta} km)`
      );

      return result;
    });
  }

  /**
   * Calculate and update fleet mileage targets for balancing.
   * Target = fleet average mileage, variance = current - target
   */
  async recalculateFleetTargets(fleetId: string): Promise<void> {
    return this.inTransaction('recalculateFleetTargets', async (tx, span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      // Get average mileage for the fleet
      const [{ avgMileage }] = await tx
        .select({ avgMileage: avg(trains.currentMileageKm) })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const targetMileage = Math.round(Number(avgMileage) || 0);
      span.setAttribute('mileage.target', targetMileage);

      // Update all trains in fleet with new target
      await tx
        .update(trains)
        .set({
          targetMileageKm: targetMileage,
          updatedAt: new Date(),
        })
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      this.log.info(
        { fleetId, targetMileage },
        'Fleet mileage targets recalculated'
      );
    });
  }

  // ===========================================================================
  // Route Operations
  // ===========================================================================

  async getRouteById(id: string): Promise<Route> {
    return this.traced('getRouteById', async (span) => {
      span.setAttribute('route.id', id);

      const result = await this.db.query.routes.findFirst({
        where: eq(routes.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Route not found: ${id}`, {
          entityType: 'route',
          entityId: id,
        });
      }

      return result;
    });
  }

  async getRouteByCode(routeCode: string): Promise<Route> {
    return this.traced('getRouteByCode', async (span) => {
      span.setAttribute('route.code', routeCode);

      const result = await this.db.query.routes.findFirst({
        where: eq(routes.routeCode, routeCode),
      });

      if (!result) {
        throw new NotFoundError(`Route not found with code: ${routeCode}`, {
          entityType: 'route',
          entityId: routeCode,
        });
      }

      return result;
    });
  }

  async listRoutes(options?: { active?: boolean }): Promise<Route[]> {
    return this.traced('listRoutes', async (span) => {
      const conditions: SQL<unknown>[] = [];
      if (options?.active !== undefined) {
        conditions.push(eq(routes.active, options.active));
      }

      const result = await this.db.query.routes.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(routes.routeCode),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createRoute(data: NewRoute): Promise<Route> {
    return this.inTransaction('createRoute', async (tx, span) => {
      span.setAttribute('route.code', data.routeCode);

      // Check for duplicate code
      const existing = await tx.query.routes.findFirst({
        where: eq(routes.routeCode, data.routeCode),
      });

      if (existing) {
        throw new DuplicateError(`Route with code ${data.routeCode} already exists`, {
          field: 'routeCode',
          value: data.routeCode,
        });
      }

      const [result] = await tx.insert(routes).values(data).returning();
      span.setAttribute('route.id', result.id);

      this.log.info({ routeId: result.id, routeCode: data.routeCode }, 'Route created');
      return result;
    });
  }

  async updateRoute(id: string, data: Partial<NewRoute>): Promise<Route> {
    return this.inTransaction('updateRoute', async (tx, span) => {
      span.setAttribute('route.id', id);

      const existing = await tx.query.routes.findFirst({
        where: eq(routes.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Route not found: ${id}`, {
          entityType: 'route',
          entityId: id,
        });
      }

      // Check for duplicate code if changing
      if (data.routeCode && data.routeCode !== existing.routeCode) {
        const duplicate = await tx.query.routes.findFirst({
          where: eq(routes.routeCode, data.routeCode),
        });
        if (duplicate) {
          throw new DuplicateError(`Route with code ${data.routeCode} already exists`, {
            field: 'routeCode',
            value: data.routeCode,
          });
        }
      }

      const [result] = await tx
        .update(routes)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(routes.id, id))
        .returning();

      return result;
    });
  }

  async deactivateRoute(id: string): Promise<Route> {
    return this.updateRoute(id, { active: false });
  }

  // ===========================================================================
  // Track Operations
  // ===========================================================================

  async getTrackById(id: string): Promise<Track> {
    return this.traced('getTrackById', async (span) => {
      span.setAttribute('track.id', id);

      const result = await this.db.query.tracks.findFirst({
        where: eq(tracks.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Track not found: ${id}`, {
          entityType: 'track',
          entityId: id,
        });
      }

      return result;
    });
  }

  async listTracks(options?: { depotId?: string; active?: boolean }): Promise<Track[]> {
    return this.traced('listTracks', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (options?.depotId) {
        conditions.push(eq(tracks.depotId, options.depotId));
        span.setAttribute(MmsAttributes.DEPOT_ID, options.depotId);
      }
      if (options?.active !== undefined) {
        conditions.push(eq(tracks.active, options.active));
      }

      const result = await this.db.query.tracks.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: asc(tracks.trackNumber),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  async createTrack(data: NewTrack): Promise<Track> {
    return this.inTransaction('createTrack', async (tx, span) => {
      span.setAttribute('track.number', data.trackNumber);
      span.setAttribute(MmsAttributes.DEPOT_ID, data.depotId);

      // Validate depot exists
      const depot = await tx.query.depots.findFirst({
        where: eq(depots.id, data.depotId),
      });
      if (!depot) {
        throw new ValidationError('Depot not found', {
          field: 'depotId',
          context: { depotId: data.depotId },
        });
      }

      // Check for duplicate track number within depot
      const existing = await tx.query.tracks.findFirst({
        where: and(eq(tracks.depotId, data.depotId), eq(tracks.trackNumber, data.trackNumber)),
      });

      if (existing) {
        throw new DuplicateError(
          `Track ${data.trackNumber} already exists in depot`,
          {
            field: 'trackNumber',
            value: data.trackNumber,
            context: { depotId: data.depotId },
          }
        );
      }

      const [result] = await tx.insert(tracks).values(data).returning();
      span.setAttribute('track.id', result.id);

      this.log.info(
        { trackId: result.id, trackNumber: data.trackNumber, depotId: data.depotId },
        'Track created'
      );
      return result;
    });
  }

  async updateTrack(id: string, data: Partial<NewTrack>): Promise<Track> {
    return this.inTransaction('updateTrack', async (tx, span) => {
      span.setAttribute('track.id', id);

      const existing = await tx.query.tracks.findFirst({
        where: eq(tracks.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Track not found: ${id}`, {
          entityType: 'track',
          entityId: id,
        });
      }

      // Check for duplicate track number if changing
      if (data.trackNumber && data.trackNumber !== existing.trackNumber) {
        const depotId = data.depotId ?? existing.depotId;
        const duplicate = await tx.query.tracks.findFirst({
          where: and(eq(tracks.depotId, depotId), eq(tracks.trackNumber, data.trackNumber)),
        });
        if (duplicate) {
          throw new DuplicateError(
            `Track ${data.trackNumber} already exists in depot`,
            {
              field: 'trackNumber',
              value: data.trackNumber,
              context: { depotId },
            }
          );
        }
      }

      // Drizzle doesn't have updatedAt on tracks schema, so just update fields
      const [result] = await tx
        .update(tracks)
        .set(data)
        .where(eq(tracks.id, id))
        .returning();

      return result;
    });
  }

  async deactivateTrack(id: string): Promise<Track> {
    return this.updateTrack(id, { active: false });
  }

  // ===========================================================================
  // Fleet Statistics
  // ===========================================================================

  /**
   * Get comprehensive statistics for a fleet
   */
  async getFleetStatistics(fleetId: string): Promise<FleetStatistics> {
    return this.traced('getFleetStatistics', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      // Verify fleet exists
      const fleet = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, fleetId),
      });

      if (!fleet) {
        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
          entityType: 'fleet',
          entityId: fleetId,
        });
      }

      // Get all stats in one query
      const statsQuery = await this.db
        .select({
          totalTrains: count(),
          totalMileageKm: sum(trains.currentMileageKm),
          averageMileageKm: avg(trains.currentMileageKm),
          minMileageKm: sql<number>`MIN(${trains.currentMileageKm})`,
          maxMileageKm: sql<number>`MAX(${trains.currentMileageKm})`,
          stdDevMileageKm: sql<number>`STDDEV(${trains.currentMileageKm})`,
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const stats = statsQuery[0];

      // Get counts by fitness status
      const fitnessCounts = await this.db
        .select({
          status: trains.fitnessStatus,
          count: count(),
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)))
        .groupBy(trains.fitnessStatus);

      const statusMap = new Map(fitnessCounts.map((fc) => [fc.status, fc.count]));

      const result: FleetStatistics = {
        fleetId,
        fleetCode: fleet.code,
        totalTrains: Number(stats.totalTrains) || 0,
        activeTrains: Number(stats.totalTrains) || 0,
        fitTrains: statusMap.get('FIT') || 0,
        restrictedTrains: statusMap.get('RESTRICTED') || 0,
        groundedTrains: statusMap.get('GROUNDED') || 0,
        totalMileageKm: Number(stats.totalMileageKm) || 0,
        averageMileageKm: Math.round(Number(stats.averageMileageKm) || 0),
        minMileageKm: Number(stats.minMileageKm) || 0,
        maxMileageKm: Number(stats.maxMileageKm) || 0,
        mileageStdDevKm: Math.round(Number(stats.stdDevMileageKm) || 0),
      };

      span.setAttribute('stats.totalTrains', result.totalTrains);
      span.setAttribute('stats.fitTrains', result.fitTrains);
      span.setAttribute('stats.avgMileage', result.averageMileageKm);

      return result;
    });
  }

  /**
   * Get statistics for all fleets
   */
  async getAllFleetStatistics(): Promise<FleetStatistics[]> {
    return this.traced('getAllFleetStatistics', async (span) => {
      const allFleets = await this.db.query.fleets.findMany({
        where: eq(fleets.active, true),
        orderBy: asc(fleets.code),
      });

      const stats = await Promise.all(
        allFleets.map((f) => this.getFleetStatistics(f.id))
      );

      span.setAttribute('result.count', stats.length);
      return stats;
    });
  }

  // ===========================================================================
  // Bulk Operations
  // ===========================================================================

  /**
   * Get multiple trains by IDs
   */
  async getTrainsByIds(ids: string[]): Promise<Train[]> {
    return this.traced('getTrainsByIds', async (span) => {
      span.setAttribute('input.count', ids.length);

      if (ids.length === 0) {
        return [];
      }

      const result = await this.db.query.trains.findMany({
        where: inArray(trains.id, ids),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Get multiple trains by train numbers
   */
  async getTrainsByNumbers(trainNumbers: string[]): Promise<Train[]> {
    return this.traced('getTrainsByNumbers', async (span) => {
      span.setAttribute('input.count', trainNumbers.length);

      if (trainNumbers.length === 0) {
        return [];
      }

      const result = await this.db.query.trains.findMany({
        where: inArray(trains.trainNumber, trainNumbers),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Check if train numbers exist (for ingestion validation)
   */
  async validateTrainNumbers(trainNumbers: string[]): Promise<{
    valid: string[];
    invalid: string[];
  }> {
    return this.traced('validateTrainNumbers', async (span) => {
      span.setAttribute('input.count', trainNumbers.length);

      if (trainNumbers.length === 0) {
        return { valid: [], invalid: [] };
      }

      const existing = await this.db.query.trains.findMany({
        where: inArray(trains.trainNumber, trainNumbers),
        columns: { trainNumber: true },
      });

      const existingSet = new Set(existing.map((t) => t.trainNumber));
      const valid: string[] = [];
      const invalid: string[] = [];

      for (const num of trainNumbers) {
        if (existingSet.has(num)) {
          valid.push(num);
        } else {
          invalid.push(num);
        }
      }

      span.setAttribute('result.valid', valid.length);
      span.setAttribute('result.invalid', invalid.length);

      return { valid, invalid };
    });
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let fleetServiceInstance: FleetService | null = null;

export function getFleetService(): FleetService {
  if (!fleetServiceInstance) {
    fleetServiceInstance = new FleetService();
  }
  return fleetServiceInstance;
}

export default FleetService;

