   750→  /**
   751→   * Update an existing service demand configuration.
   752→   */
   753→  async updateDemand(
   754→    id: string,
   755→    data: Partial<Omit<CreateDemandRequest, 'fleetId' | 'effectiveDate' | 'dayType'>>
   756→  ): Promise<ServiceDemand> {
   757→    return this.inTransaction('updateDemand', async (tx, span) => {
   758→      span.setAttribute('demand.id', id);
   759→
   760→      const existing = await tx.query.serviceDemand.findFirst({
   761→        where: eq(serviceDemand.id, id),
   762→        with: { fleet: true },
   763→      });
   764→
   765→      if (!existing) {
   766→        throw new NotFoundError(`Service demand not found: ${id}`, {
   767→          entityType: 'service_demand',
   768→          entityId: id,
   769→        });
   770→      }
   771→
   772→      // Validate minTrainsRequired if changing
   773→      if (data.minTrainsRequired !== undefined) {
   774→        const [{ totalTrains }] = await tx
   775→          .select({ totalTrains: count() })
   776→          .from(trains)
   777→          .where(and(eq(trains.fleetId, existing.fleetId), eq(trains.active, true)));
   778→
   779→        if (data.minTrainsRequired > totalTrains) {
   780→          throw new ValidationError(
   781→            `Minimum trains required (${data.minTrainsRequired}) exceeds fleet size (${totalTrains})`,
   782→            {
   783→              field: 'minTrainsRequired',
   784→              context: { minTrainsRequired: data.minTrainsRequired, fleetSize: totalTrains },
   785→            }
   786→          );
   787→        }
   788→      }
   789→
   790→      const [result] = await tx
   791→        .update(serviceDemand)
   792→        .set({
   793→          ...data,
   794→          updatedAt: new Date(),
   795→        })
   796→        .where(eq(serviceDemand.id, id))
   797→        .returning();
   798→
   799→      this.log.info(
   800→        { demandId: id, updates: data },
   801→        'Service demand updated'
   802→      );
   803→
   804→      return result;
   805→    });
   806→  }
