   815→      const result = await this.db.query.serviceDemand.findFirst({
   816→        where: eq(serviceDemand.id, id),
   817→      });
   818→
   819→      if (!result) {
   820→        throw new NotFoundError(`Service demand not found: ${id}`, {
   821→          entityType: 'service_demand',
   822→          entityId: id,
   823→        });
   824→      }
   825→
   826→      return result;
   827→    });
   828→  }
   829→
   830→  /**
   831→   * List demand configurations with filtering.
   832→   */
   833→  async listDemand(filters?: DemandListFilters): Promise<ServiceDemand[]> {
   834→    return this.traced('listDemand', async (span) => {
   835→      const conditions: SQL<unknown>[] = [];
   836→
   837→      if (filters?.fleetId) {
   838→        conditions.push(eq(serviceDemand.fleetId, filters.fleetId));
   839→      }
   840→      if (filters?.dayType) {
   841→        if (Array.isArray(filters.dayType)) {
   842→          conditions.push(inArray(serviceDemand.dayType, filters.dayType));
   843→        } else {
   844→          conditions.push(eq(serviceDemand.dayType, filters.dayType));
   845→        }
   846→      }
   847→      if (filters?.effectiveDateFrom) {
