   856→        orderBy: [desc(serviceDemand.effectiveDate), desc(serviceDemand.dayType)],
   857→      });
   858→
   859→      span.setAttribute('result.count', result.length);
   860→      return result;
   861→    });
   862→  }
   863→
   864→  /**
   865→   * Delete a demand configuration.
   866→   */
   867→  async deleteDemand(id: string): Promise<void> {
   868→    return this.inTransaction('deleteDemand', async (tx, span) => {
   869→      span.setAttribute('demand.id', id);
   870→
   871→      const existing = await tx.query.serviceDemand.findFirst({
   872→        where: eq(serviceDemand.id, id),
