   969→      );
   970→
   971→      return summaries;
   972→    });
   973→  }
   974→
   975→  // ===========================================================================
   976→  // Helper Methods
   977→  // ===========================================================================
   978→
   979→  /**
   980→   * Determine day type for a given date.
   981→   *
   982→   * @param dateStr - Date string (YYYY-MM-DD)
   983→   * @param holidays - Optional array of holiday dates
   984→   * @returns Day type enum value
   985→   */
   986→  getDayType(dateStr: string, holidays?: string[]): DayType {
   987→    // Check if it's a holiday first
   988→    if (holidays?.includes(dateStr)) {
   989→      return 'HOLIDAY';
   990→    }
   991→
   992→    const date = new Date(dateStr);
   993→    const dayOfWeek = date.getDay();
   994→
   995→    if (dayOfWeek === 0) return 'SUNDAY';
   996→    if (dayOfWeek === 6) return 'SATURDAY';
   997→    return 'WEEKDAY';
   998→  }
   999→
  1000→  /**
  1001→   * Calculate default demand when no config exists.
  1002→   * Uses 85% of fleet size as the default requirement.
  1003→   */
  1004→  private async calculateDefaultDemand(
  1005→    fleetId: string
  1006→  ): Promise<{ minTrainsRequired: number }> {
  1007→    const [{ totalTrains }] = await this.db
  1008→      .select({ totalTrains: count() })
  1009→      .from(trains)
  1010→      .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
  1011→
  1012→    const minTrainsRequired = Math.ceil(totalTrains * DEFAULT_AVAILABILITY_PCT);
  1013→
  1014→    return { minTrainsRequired };
  1015→  }
  1016→}
