   280→  // ===========================================================================
   281→  // Daily Rate Calculation
   282→  // ===========================================================================
   283→
   284→  /**
   285→   * Calculate expected daily km for a train based on available data.
   286→   *
   287→   * This is the primary method for mileage projection. It follows the
   288→   * fallback hierarchy:
   289→   * 1. Route-specific profile (if train has assigned route or default route)
   290→   * 2. Fleet-wide average from recent mileage readings
   291→   * 3. System default (250 km/day)
   292→   *
   293→   * The result includes source and confidence metadata for transparency.
   294→   *
   295→   * @param trainId - Train UUID
   296→   * @param targetDate - Date to calculate rate for
   297→   * @param routeId - Optional specific route ID (if known)
   298→   * @param holidays - Optional array of holiday dates (YYYY-MM-DD)
   299→   * @returns Daily rate with source and confidence
   300→   */
   301→  async calculateDailyRate(
   302→    trainId: string,
   303→    targetDate: string,
   304→    routeId?: string,
   305→    holidays?: string[]
   306→  ): Promise<DailyRateResult> {
   307→    return this.traced('calculateDailyRate', async (span) => {
   308→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   309→      span.setAttribute('rate.targetDate', targetDate);
   310→
   311→      // Get train details
   312→      const train = await this.db.query.trains.findFirst({
   313→        where: eq(trains.id, trainId),
   314→        with: { fleet: true },
   315→      });
   316→
   317→      if (!train) {
   318→        throw new NotFoundError(`Train not found: ${trainId}`, {
   319→          entityType: 'train',
   320→          entityId: trainId,
   321→        });
   322→      }
   323→
   324→      span.setAttribute(MmsAttributes.FLEET_ID, train.fleetId);
   325→
   326→      // Determine day type
   327→      const dayType = this.getDayType(targetDate, holidays);
   328→      span.setAttribute('rate.dayType', dayType);
   329→
   330→      // Try route-specific profile first
   331→      if (routeId) {
   332→        const profile = await this.getProfile(routeId, targetDate);
   333→        if (profile) {
   334→          const result = this.calculateFromProfile(profile, targetDate, dayType);
   335→          span.setAttribute('rate.source', result.source);
   336→          span.setAttribute('rate.dailyKm', result.dailyKm);
   337→          span.setAttribute('rate.confidence', result.confidence);
   338→          return result;
   339→        }
   340→      }
   341→
   342→      // Try fleet's default route (if defined)
   343→      // TODO: When run assignment history is available, look up typical route assignment
   344→
   345→      // Fall back to fleet average
   346→      const fleetAverage = await this.getFleetAverage(train.fleetId, targetDate);
   347→      if (fleetAverage && fleetAverage.sampleSize >= MIN_SAMPLE_SIZE_FOR_MEDIUM_CONFIDENCE) {
   348→        const result: DailyRateResult = {
   349→          dailyKm: Math.round(fleetAverage.averageDailyKm),
   350→          source: 'fleet_average',
   351→          confidence: fleetAverage.confidence,
   352→          details: {
   353→            fleetId: train.fleetId,
   354→            fleetCode: train.fleet?.code,
   355→            dayType,
   356→          },
   357→        };
   358→
   359→        span.setAttribute('rate.source', result.source);
   360→        span.setAttribute('rate.dailyKm', result.dailyKm);
   361→        span.setAttribute('rate.confidence', result.confidence);
   362→
   363→        this.log.debug(
   364→          {
   365→            trainId,
   366→            fleetId: train.fleetId,
   367→            dailyKm: result.dailyKm,
   368→            sampleSize: fleetAverage.sampleSize,
   369→          },
   370→          `Using fleet average for train ${train.trainNumber}: ${result.dailyKm} km/day`
   371→        );
   372→
   373→        return result;
   374→      }
   375→
   376→      // Fall back to system default
   377→      const result: DailyRateResult = {
   378→        dailyKm: SYSTEM_DEFAULT_DAILY_KM,
   379→        source: 'system_default',
   380→        confidence: 'ESTIMATED',
   381→        details: {
   382→          fleetId: train.fleetId,
   383→          fleetCode: train.fleet?.code,
   384→          dayType,
   385→        },
   386→      };
   387→
   388→      span.setAttribute('rate.source', result.source);
   389→      span.setAttribute('rate.dailyKm', result.dailyKm);
   390→      span.setAttribute('rate.confidence', result.confidence);
   391→
   392→      this.log.warn(
   393→        {
   394→          trainId,
   395→          trainNumber: train.trainNumber,
   396→          fleetId: train.fleetId,
   397→          targetDate,
   398→        },
   399→        `No route profile or fleet average for train ${train.trainNumber}. Using system default ${SYSTEM_DEFAULT_DAILY_KM} km/day. This may cause significant projection errors over time.`
   400→      );
   401→
   402→      return result;
   403→    });
   404→  }
