   406→  /**
   407→   * Calculate rate for a specific route (without train context).
   408→   *
   409→   * Used when planning route-level capacity or before train assignment.
   410→   */
   411→  async calculateRouteRate(
   412→    routeId: string,
   413→    targetDate: string,
   414→    holidays?: string[]
   415→  ): Promise<DailyRateResult> {
   416→    return this.traced('calculateRouteRate', async (span) => {
   417→      span.setAttribute('route.id', routeId);
   418→      span.setAttribute('rate.targetDate', targetDate);
   419→
   420→      // Verify route exists
   421→      const route = await this.db.query.routes.findFirst({
   422→        where: eq(routes.id, routeId),
   423→      });
   424→
   425→      if (!route) {
   426→        throw new NotFoundError(`Route not found: ${routeId}`, {
   427→          entityType: 'route',
   428→          entityId: routeId,
   429→        });
   430→      }
   431→
   432→      const dayType = this.getDayType(targetDate, holidays);
   433→      span.setAttribute('rate.dayType', dayType);
   434→
   435→      // Try route-specific profile
   436→      const profile = await this.getProfile(routeId, targetDate);
   437→      if (profile) {
   438→        const result = this.calculateFromProfile(profile, targetDate, dayType);
   439→        span.setAttribute('rate.source', result.source);
   440→        span.setAttribute('rate.dailyKm', result.dailyKm);
   441→        return result;
   442→      }
   443→
   444→      // Fall back to route's default daily km if defined
   445→      if (route.defaultDailyKm) {
   446→        const result: DailyRateResult = {
   447→          dailyKm: route.defaultDailyKm,
   448→          source: `route:${routeId}`,
   449→          confidence: 'LOW',
   450→          details: {
   451→            routeId,
   452→            routeCode: route.routeCode,
   453→            dayType,
   454→          },
   455→        };
   456→        span.setAttribute('rate.source', result.source);
   457→        span.setAttribute('rate.dailyKm', result.dailyKm);
   458→        return result;
   459→      }
   460→
   461→      // Fall back to expected km per day
   462→      if (route.expectedKmPerDay) {
   463→        const multiplier = DEFAULT_DAY_TYPE_MULTIPLIERS[dayType];
   464→        const result: DailyRateResult = {
   465→          dailyKm: Math.round(route.expectedKmPerDay * multiplier),
   466→          source: `route:${routeId}`,
   467→          confidence: 'LOW',
   468→          details: {
   469→            routeId,
   470→            routeCode: route.routeCode,
   471→            dayType,
   472→          },
   473→        };
   474→        span.setAttribute('rate.source', result.source);
   475→        span.setAttribute('rate.dailyKm', result.dailyKm);
   476→        return result;
   477→      }
   478→
   479→      // System default
   480→      const result: DailyRateResult = {
   481→        dailyKm: SYSTEM_DEFAULT_DAILY_KM,
   482→        source: 'system_default',
   483→        confidence: 'ESTIMATED',
   484→        details: {
   485→          routeId,
   486→          routeCode: route.routeCode,
   487→          dayType,
   488→        },
   489→      };
   490→      span.setAttribute('rate.source', result.source);
   491→      span.setAttribute('rate.dailyKm', result.dailyKm);
   492→      return result;
   493→    });
   494→  }
   495→
   496→  // ===========================================================================
   497→  // Mileage Projection
   498→  // ===========================================================================
   499→
   500→  /**
   501→   * Project mileage for a train over a time horizon.
   502→   *
   503→   * Starting from the train's current mileage, calculates daily projections
   504→   * for the specified number of days. This is used by:
   505→   * - PM scheduling (determine when train will hit maintenance thresholds)
   506→   * - Drift monitoring (compare projected vs. actual)
   507→   * - Strategic planning (long-term fleet mileage distribution)
   508→   *
   509→   * @param trainId - Train UUID
   510→   * @param startDate - Projection start date (YYYY-MM-DD)
   511→   * @param horizonDays - Number of days to project
   512→   * @param routeId - Optional fixed route for all projections
   513→   * @param holidays - Optional array of holiday dates
   514→   * @returns Array of daily projections with cumulative mileage
   515→   */
   516→  async projectMileage(
   517→    trainId: string,
   518→    startDate: string,
   519→    horizonDays: number,
   520→    routeId?: string,
   521→    holidays?: string[]
   522→  ): Promise<MileageProjection[]> {
   523→    return this.traced('projectMileage', async (span) => {
   524→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   525→      span.setAttribute('projection.startDate', startDate);
   526→      span.setAttribute('projection.horizonDays', horizonDays);
   527→
   528→      if (horizonDays < 1) {
   529→        throw new ValidationError('Horizon days must be at least 1', {
   530→          field: 'horizonDays',
   531→          context: { value: horizonDays },
   532→        });
   533→      }
   534→
   535→      if (horizonDays > 3650) {
   536→        throw new ValidationError('Horizon days cannot exceed 3650 (10 years)', {
   537→          field: 'horizonDays',
   538→          context: { value: horizonDays },
   539→        });
   540→      }
   541→
   542→      // Get train's current mileage
   543→      const train = await this.db.query.trains.findFirst({
   544→        where: eq(trains.id, trainId),
   545→      });
   546→
   547→      if (!train) {
   548→        throw new NotFoundError(`Train not found: ${trainId}`, {
   549→          entityType: 'train',
   550→          entityId: trainId,
   551→        });
   552→      }
   553→
   554→      let cumulativeKm = train.currentMileageKm;
   555→      const projections: MileageProjection[] = [];
   556→      const start = new Date(startDate);
   557→
   558→      // Calculate daily projections
   559→      for (let day = 0; day < horizonDays; day++) {
   560→        const targetDate = addDays(start, day);
   561→        const dateStr = targetDate.toISOString().split('T')[0];
   562→
   563→        const rate = await this.calculateDailyRate(trainId, dateStr, routeId, holidays);
   564→        cumulativeKm += rate.dailyKm;
   565→
   566→        projections.push({
   567→          date: dateStr,
   568→          projectedDailyKm: rate.dailyKm,
   569→          cumulativeKm,
   570→          source: rate.source,
   571→          confidence: rate.confidence,
   572→        });
   573→      }
   574→
   575→      span.setAttribute('projection.count', projections.length);
   576→      span.setAttribute(
   577→        'projection.finalCumulativeKm',
   578→        projections[projections.length - 1]?.cumulativeKm ?? cumulativeKm
   579→      );
   580→
   581→      return projections;
   582→    });
   583→  }
   584→
   585→  /**
   586→   * Project when a train will reach a target mileage.
   587→   *
   588→   * Useful for PM scheduling - determines the date when a train will hit
   589→   * the next maintenance threshold.
   590→   *
   591→   * @param trainId - Train UUID
   592→   * @param targetMileageKm - Target cumulative mileage to reach
   593→   * @param maxHorizonDays - Maximum days to search (default: 365)
   594→   * @returns Projected date and details, or null if not reached within horizon
   595→   */
   596→  async projectDateForMileage(
   597→    trainId: string,
   598→    targetMileageKm: number,
   599→    maxHorizonDays: number = 365,
   600→    routeId?: string,
   601→    holidays?: string[]
   602→  ): Promise<{
   603→    projectedDate: string;
   604→    daysFromNow: number;
   605→    projectedMileage: number;
   606→    confidence: ConfidenceLevel;
   607→  } | null> {
   608→    return this.traced('projectDateForMileage', async (span) => {
   609→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   610→      span.setAttribute('target.mileageKm', targetMileageKm);
   611→      span.setAttribute('target.maxHorizonDays', maxHorizonDays);
   612→
   613→      // Get train's current mileage
   614→      const train = await this.db.query.trains.findFirst({
   615→        where: eq(trains.id, trainId),
   616→      });
   617→
   618→      if (!train) {
   619→        throw new NotFoundError(`Train not found: ${trainId}`, {
   620→          entityType: 'train',
   621→          entityId: trainId,
   622→        });
   623→      }
   624→
   625→      if (train.currentMileageKm >= targetMileageKm) {
   626→        span.setAttribute('result.alreadyReached', true);
   627→        return {
   628→          projectedDate: new Date().toISOString().split('T')[0],
   629→          daysFromNow: 0,
   630→          projectedMileage: train.currentMileageKm,
   631→          confidence: 'HIGH',
   632→        };
   633→      }
   634→
   635→      const startDate = new Date().toISOString().split('T')[0];
   636→      let cumulativeKm = train.currentMileageKm;
   637→      const start = new Date(startDate);
   638→      let worstConfidence: ConfidenceLevel = 'HIGH';
   639→
   640→      for (let day = 1; day <= maxHorizonDays; day++) {
   641→        const targetDate = addDays(start, day);
   642→        const dateStr = targetDate.toISOString().split('T')[0];
   643→
   644→        const rate = await this.calculateDailyRate(trainId, dateStr, routeId, holidays);
   645→        cumulativeKm += rate.dailyKm;
   646→
   647→        // Track worst confidence level
   648→        if (this.confidenceRank(rate.confidence) < this.confidenceRank(worstConfidence)) {
   649→          worstConfidence = rate.confidence;
   650→        }
   651→
   652→        if (cumulativeKm >= targetMileageKm) {
   653→          span.setAttribute('result.found', true);
   654→          span.setAttribute('result.projectedDate', dateStr);
   655→          span.setAttribute('result.daysFromNow', day);
   656→          return {
   657→            projectedDate: dateStr,
   658→            daysFromNow: day,
   659→            projectedMileage: cumulativeKm,
   660→            confidence: worstConfidence,
   661→          };
   662→        }
   663→      }
   664→
   665→      span.setAttribute('result.found', false);
   666→      span.setAttribute('result.reachedMileage', cumulativeKm);
   667→      return null;
   668→    });
   669→  }
