   671→  // ===========================================================================
   672→  // Fleet Average Calculation
   673→  // ===========================================================================
   674→
   675→  /**
   676→   * Calculate fleet-wide average daily km from recent mileage readings.
   677→   *
   678→   * Uses the last 30 days of validated mileage readings to compute
   679→   * a reliable average. Returns confidence based on sample size.
   680→   *
   681→   * @param fleetId - Fleet UUID
   682→   * @param asOfDate - Calculate as of this date (defaults to today)
   683→   * @returns Fleet average with metadata, or null if no data
   684→   */
   685→  async getFleetAverage(
   686→    fleetId: string,
   687→    asOfDate?: string
   688→  ): Promise<FleetAverageResult | null> {
   689→    return this.traced('getFleetAverage', async (span) => {
   690→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
   691→
   692→      const endDate = asOfDate ?? new Date().toISOString().split('T')[0];
   693→      const startDate = addDays(new Date(endDate), -FLEET_AVERAGE_LOOKBACK_DAYS)
   694→        .toISOString()
   695→        .split('T')[0];
   696→
   697→      span.setAttribute('average.startDate', startDate);
   698→      span.setAttribute('average.endDate', endDate);
   699→
   700→      // Get fleet for validation and metadata
   701→      const fleet = await this.db.query.fleets.findFirst({
   702→        where: eq(fleets.id, fleetId),
   703→      });
   704→
   705→      if (!fleet) {
   706→        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
   707→          entityType: 'fleet',
   708→          entityId: fleetId,
   709→        });
   710→      }
   711→
   712→      // Calculate average from valid mileage readings
   713→      const result = await this.db
   714→        .select({
   715→          avgDaily: avg(mileageReadings.dailyKm),
   716→          sampleSize: sql<number>`COUNT(*)::int`,
   717→        })
   718→        .from(mileageReadings)
   719→        .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
   720→        .where(
   721→          and(
   722→            eq(trains.fleetId, fleetId),
   723→            eq(trains.active, true),
   724→            gte(mileageReadings.readingDate, startDate),
   725→            lte(mileageReadings.readingDate, endDate),
   726→            eq(mileageReadings.validationStatus, 'VALID'),
   727→            sql`${mileageReadings.dailyKm} > 0` // Exclude zero or null readings
   728→          )
   729→        );
   730→
   731→      const { avgDaily, sampleSize } = result[0];
   732→
   733→      if (!avgDaily || sampleSize === 0) {
   734→        span.setAttribute('average.found', false);
   735→        this.log.debug(
   736→          { fleetId, fleetCode: fleet.code, startDate, endDate },
   737→          `No valid mileage readings found for fleet ${fleet.code}`
   738→        );
   739→        return null;
   740→      }
   741→
   742→      // Determine confidence based on sample size
   743→      let confidence: ConfidenceLevel;
   744→      if (sampleSize >= MIN_SAMPLE_SIZE_FOR_HIGH_CONFIDENCE) {
   745→        confidence = 'MEDIUM'; // Fleet average is never "HIGH" - route-specific is preferred
   746→      } else if (sampleSize >= MIN_SAMPLE_SIZE_FOR_MEDIUM_CONFIDENCE) {
   747→        confidence = 'LOW';
   748→      } else {
   749→        confidence = 'ESTIMATED';
   750→      }
   751→
   752→      span.setAttribute('average.found', true);
   753→      span.setAttribute('average.value', Number(avgDaily));
   754→      span.setAttribute('average.sampleSize', sampleSize);
   755→      span.setAttribute('average.confidence', confidence);
   756→
   757→      return {
   758→        fleetId,
   759→        fleetCode: fleet.code,
   760→        averageDailyKm: Math.round(Number(avgDaily)),
   761→        sampleSize,
   762→        periodStart: startDate,
   763→        periodEnd: endDate,
   764→        confidence,
   765→      };
   766→    });
   767→  }
