   773→  /**
   774→   * Create a new route utilization profile.
   775→   */
   776→  async createProfile(request: CreateProfileRequest): Promise<RouteUtilizationProfile> {
   777→    return this.inTransaction('createProfile', async (tx, span) => {
   778→      const {
   779→        routeId,
   780→        effectiveDate = new Date().toISOString().split('T')[0],
   781→        weekdayKm,
   782→        saturdayKm,
   783→        sundayKm,
   784→        holidayKm,
   785→        peakSeasonMultiplier = 1.0,
   786→        offPeakMultiplier = 1.0,
   787→        serviceHoursPerDay,
   788→        roundTripKm,
   789→        tripsPerDay,
   790→        source,
   791→        confidence = 'MEDIUM',
   792→        notes,
   793→      } = request;
   794→
   795→      span.setAttribute('route.id', routeId);
   796→      span.setAttribute('profile.effectiveDate', effectiveDate);
   797→
   798→      // Verify route exists
   799→      const route = await tx.query.routes.findFirst({
   800→        where: eq(routes.id, routeId),
   801→      });
   802→
   803→      if (!route) {
   804→        throw new NotFoundError(`Route not found: ${routeId}`, {
   805→          entityType: 'route',
   806→          entityId: routeId,
   807→        });
   808→      }
   809→
   810→      // Validate weekdayKm
   811→      if (weekdayKm < 0 || weekdayKm > 2000) {
   812→        throw new ValidationError('Weekday km must be between 0 and 2000', {
   813→          field: 'weekdayKm',
   814→          context: { value: weekdayKm },
   815→        });
   816→      }
   817→
   818→      // Check for duplicate (same route and effective date)
   819→      const existing = await tx.query.routeUtilizationProfiles.findFirst({
   820→        where: and(
   821→          eq(routeUtilizationProfiles.routeId, routeId),
   822→          eq(routeUtilizationProfiles.effectiveDate, effectiveDate)
   823→        ),
   824→      });
   825→
   826→      if (existing) {
   827→        throw new DuplicateError(
   828→          `Profile already exists for route ${route.routeCode} on ${effectiveDate}`,
   829→          {
   830→            field: 'effectiveDate',
   831→            value: effectiveDate,
   832→            context: { routeId, routeCode: route.routeCode },
   833→          }
   834→        );
   835→      }
   836→
   837→      // Create profile
   838→      const profileData: NewRouteUtilizationProfile = {
   839→        routeId,
   840→        effectiveDate,
   841→        weekdayKm,
   842→        saturdayKm: saturdayKm ?? null,
   843→        sundayKm: sundayKm ?? null,
   844→        holidayKm: holidayKm ?? null,
   845→        peakSeasonMultiplier: peakSeasonMultiplier.toString(),
   846→        offPeakMultiplier: offPeakMultiplier.toString(),
   847→        serviceHoursPerDay: serviceHoursPerDay?.toString() ?? null,
   848→        roundTripKm: roundTripKm?.toString() ?? null,
   849→        tripsPerDay: tripsPerDay ?? null,
   850→        source: source ?? null,
   851→        confidence,
   852→        notes: notes ?? null,
   853→      };
   854→
   855→      const [result] = await tx
   856→        .insert(routeUtilizationProfiles)
   857→        .values(profileData)
   858→        .returning();
   859→
   860→      span.setAttribute('profile.id', result.id);
   861→
   862→      this.log.info(
   863→        {
   864→          profileId: result.id,
   865→          routeId,
   866→          routeCode: route.routeCode,
   867→          effectiveDate,
   868→          weekdayKm,
   869→          confidence,
   870→        },
   871→        `Created route utilization profile for ${route.routeCode}: ${weekdayKm} km/day (weekday)`
   872→      );
   873→
   874→      return result;
   875→    });
   876→  }
