   886→      span.setAttribute('profile.id', id);
   887→
   888→      const existing = await tx.query.routeUtilizationProfiles.findFirst({
   889→        where: eq(routeUtilizationProfiles.id, id),
   890→        with: { route: true },
   891→      });
   892→
   893→      if (!existing) {
   894→        throw new NotFoundError(`Route utilization profile not found: ${id}`, {
   895→          entityType: 'route_utilization_profile',
   896→          entityId: id,
   897→        });
   898→      }
   899→
   900→      // Validate weekdayKm if changing
   901→      if (data.weekdayKm !== undefined && (data.weekdayKm < 0 || data.weekdayKm > 2000)) {
   902→        throw new ValidationError('Weekday km must be between 0 and 2000', {
   903→          field: 'weekdayKm',
   904→          context: { value: data.weekdayKm },
   905→        });
   906→      }
   907→
   908→      // Build update object
   909→      const updateData: Record<string, unknown> = { updatedAt: new Date() };
   910→
   911→      if (data.weekdayKm !== undefined) updateData.weekdayKm = data.weekdayKm;
   912→      if (data.saturdayKm !== undefined) updateData.saturdayKm = data.saturdayKm;
   913→      if (data.sundayKm !== undefined) updateData.sundayKm = data.sundayKm;
   914→      if (data.holidayKm !== undefined) updateData.holidayKm = data.holidayKm;
   915→      if (data.peakSeasonMultiplier !== undefined) {
   916→        updateData.peakSeasonMultiplier = data.peakSeasonMultiplier.toString();
   917→      }
   918→      if (data.offPeakMultiplier !== undefined) {
   919→        updateData.offPeakMultiplier = data.offPeakMultiplier.toString();
   920→      }
   921→      if (data.serviceHoursPerDay !== undefined) {
   922→        updateData.serviceHoursPerDay = data.serviceHoursPerDay?.toString() ?? null;
   923→      }
   924→      if (data.roundTripKm !== undefined) {
   925→        updateData.roundTripKm = data.roundTripKm?.toString() ?? null;
   926→      }
   927→      if (data.tripsPerDay !== undefined) updateData.tripsPerDay = data.tripsPerDay;
   928→      if (data.source !== undefined) updateData.source = data.source;
   929→      if (data.confidence !== undefined) updateData.confidence = data.confidence;
   930→      if (data.notes !== undefined) updateData.notes = data.notes;
   931→
   932→      const [result] = await tx
   933→        .update(routeUtilizationProfiles)
   934→        .set(updateData)
   935→        .where(eq(routeUtilizationProfiles.id, id))
   936→        .returning();
   937→
   938→      this.log.info(
   939→        { profileId: id, updates: data },
   940→        'Route utilization profile updated'
   941→      );
   942→
   943→      return result;
   944→    });
   945→  }
   946→
   947→  /**
   948→   * List profiles with filtering.
   949→   */
   950→  async listProfiles(filters?: ProfileListFilters): Promise<RouteProfileWithMeta[]> {
   951→    return this.traced('listProfiles', async (span) => {
   952→      const conditions: SQL<unknown>[] = [];
   953→
   954→      if (filters?.routeId) {
   955→        conditions.push(eq(routeUtilizationProfiles.routeId, filters.routeId));
   956→      }
   957→      if (filters?.routeIds && filters.routeIds.length > 0) {
   958→        conditions.push(inArray(routeUtilizationProfiles.routeId, filters.routeIds));
   959→      }
   960→      if (filters?.confidence) {
   961→        if (Array.isArray(filters.confidence)) {
   962→          conditions.push(inArray(routeUtilizationProfiles.confidence, filters.confidence));
   963→        } else {
   964→          conditions.push(eq(routeUtilizationProfiles.confidence, filters.confidence));
   965→        }
   966→      }
   967→      if (filters?.effectiveDateFrom) {
   968→        conditions.push(gte(routeUtilizationProfiles.effectiveDate, filters.effectiveDateFrom));
   969→      }
   970→      if (filters?.effectiveDateTo) {
   971→        conditions.push(lte(routeUtilizationProfiles.effectiveDate, filters.effectiveDateTo));
   972→      }
   973→
   974→      const profiles = await this.db.query.routeUtilizationProfiles.findMany({
   975→        where: conditions.length > 0 ? and(...conditions) : undefined,
   976→        orderBy: [desc(routeUtilizationProfiles.effectiveDate)],
   977→        with: { route: true },
   978→      });
   979→
   980→      span.setAttribute('result.count', profiles.length);
   981→
   982→      return profiles.map((p) => ({
   983→        ...p,
   984→        routeCode: p.route?.routeCode,
   985→        routeName: p.route?.routeName,
   986→      }));
   987→    });
   988→  }
   989→
   990→  /**
   991→   * Delete a profile.
   992→   */
   993→  async deleteProfile(id: string): Promise<void> {
   994→    return this.inTransaction('deleteProfile', async (tx, span) => {
   995→      span.setAttribute('profile.id', id);
   996→
   997→      const existing = await tx.query.routeUtilizationProfiles.findFirst({
   998→        where: eq(routeUtilizationProfiles.id, id),
   999→        with: { route: true },
  1000→      });
  1001→
  1002→      if (!existing) {
  1003→        throw new NotFoundError(`Route utilization profile not found: ${id}`, {
  1004→          entityType: 'route_utilization_profile',
  1005→          entityId: id,
  1006→        });
  1007→      }
  1008→
  1009→      await tx.delete(routeUtilizationProfiles).where(eq(routeUtilizationProfiles.id, id));
  1010→
  1011→      this.log.info(
  1012→        {
  1013→          profileId: id,
  1014→          routeId: existing.routeId,
  1015→          routeCode: existing.route?.routeCode,
  1016→          effectiveDate: existing.effectiveDate,
  1017→        },
  1018→        `Deleted route utilization profile for ${existing.route?.routeCode}`
  1019→      );
  1020→    });
  1021→  }
  1022→
  1023→  // ===========================================================================
  1024→  // Helper Methods
  1025→  // ===========================================================================
  1026→
  1027→  /**
  1028→   * Determine day type for a given date.
  1029→   */
  1030→  getDayType(dateStr: string, holidays?: string[]): UtilizationDayType {
  1031→    if (holidays?.includes(dateStr)) {
  1032→      return 'HOLIDAY';
  1033→    }
  1034→
  1035→    const date = new Date(dateStr);
  1036→    const dayOfWeek = date.getDay();
  1037→
  1038→    if (dayOfWeek === 0) return 'SUNDAY';
  1039→    if (dayOfWeek === 6) return 'SATURDAY';
  1040→    return 'WEEKDAY';
  1041→  }
  1042→
  1043→  /**
  1044→   * Check if a date is in peak season.
  1045→   */
  1046→  isPeakSeason(dateStr: string): boolean {
  1047→    const date = new Date(dateStr);
  1048→    return PEAK_MONTHS.includes(date.getMonth());
  1049→  }
  1050→
  1051→  /**
  1052→   * Calculate daily rate from a route profile.
  1053→   */
  1054→  private calculateFromProfile(
  1055→    profile: RouteUtilizationProfile,
  1056→    targetDate: string,
  1057→    dayType: UtilizationDayType
  1058→  ): DailyRateResult {
  1059→    // Get base km for day type
  1060→    let baseKm: number;
  1061→    switch (dayType) {
  1062→      case 'SATURDAY':
  1063→        baseKm = profile.saturdayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.SATURDAY);
  1064→        break;
  1065→      case 'SUNDAY':
  1066→        baseKm = profile.sundayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.SUNDAY);
  1067→        break;
  1068→      case 'HOLIDAY':
  1069→        baseKm = profile.holidayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.HOLIDAY);
  1070→        break;
  1071→      default:
  1072→        baseKm = profile.weekdayKm;
  1073→    }
  1074→
  1075→    // Apply seasonal multiplier
  1076→    const isPeak = this.isPeakSeason(targetDate);
  1077→    const multiplier = isPeak
  1078→      ? parseFloat(profile.peakSeasonMultiplier ?? '1.0')
  1079→      : parseFloat(profile.offPeakMultiplier ?? '1.0');
  1080→
  1081→    const dailyKm = Math.round(baseKm * multiplier);
  1082→
  1083→    return {
  1084→      dailyKm,
  1085→      source: `route:${profile.routeId}`,
  1086→      confidence: (profile.confidence ?? 'MEDIUM') as ConfidenceLevel,
  1087→      details: {
  1088→        routeId: profile.routeId,
  1089→        dayType,
  1090→        seasonalMultiplier: multiplier,
  1091→        profileEffectiveDate: profile.effectiveDate,
  1092→      },
  1093→    };
  1094→  }
  1095→
  1096→  /**
  1097→   * Get numeric rank for confidence level (higher = better).
  1098→   */
  1099→  private confidenceRank(confidence: ConfidenceLevel): number {
  1100→    switch (confidence) {
  1101→      case 'HIGH':
  1102→        return 4;
  1103→      case 'MEDIUM':
  1104→        return 3;
  1105→      case 'LOW':
  1106→        return 2;
  1107→      case 'ESTIMATED':
  1108→        return 1;
  1109→    }
  1110→  }
  1111→}
  1112→
  1113→// =============================================================================
  1114→// Singleton Export
  1115→// =============================================================================
  1116→
  1117→let routeUtilizationServiceInstance: RouteUtilizationService | null = null;
  1118→
  1119→export function getRouteUtilizationService(): RouteUtilizationService {
  1120→  if (!routeUtilizationServiceInstance) {
