   295→        {
   296→          attempts: 3,
   297→          backoff: { type: 'exponential', delay: 5000 },
   298→        }
   299→      );
   300→
   301→      this.lastFileReceivedAt = new Date();
   302→
   303→      this.log.info(
   304→        { jobId: id, fileName, fileSize: validation.fileSize, uploadedBy },
