   312→  /**
   313→   * Process a mileage CSV file (main ingestion entry point)
   314→   *
   315→   * This is the core method called by the ingestion worker.
   316→   */
   317→  async processFile(
   318→    filePath: string,
   319→    jobId: string = crypto.randomUUID()
   320→  ): Promise<IngestionResult> {
   321→    return this.traced('processFile', async (span) => {
   322→      const startTime = Date.now();
   323→      const fileName = path.basename(filePath);
   324→
   325→      span.setAttribute(MmsAttributes.INGESTION_FILE, fileName);
   326→      span.setAttribute(MmsAttributes.INGESTION_JOB_ID, jobId);
   327→
   328→      ingestionMetrics.filesReceived.inc();
   329→
   330→      const result: IngestionResult = {
   331→        jobId,
   332→        fileName,
   333→        totalRecords: 0,
   334→        validRecords: 0,
   335→        invalidRecords: 0,
   336→        anomalies: [],
   337→        meterEvents: [],
   338→        processingTimeMs: 0,
   339→        trainsUpdated: 0,
   340→        status: 'SUCCESS',
   341→      };
   342→
   343→      try {
   344→        // Parse CSV
   345→        const records = await this.parseCsv(filePath);
   346→        result.totalRecords = records.length;
   347→        span.setAttribute(MmsAttributes.INGESTION_RECORD_COUNT, records.length);
   348→
   349→        ingestionMetrics.recordsProcessed.inc(records.length);
   350→
   351→        if (records.length === 0) {
   352→          result.status = 'PARTIAL';
   353→          result.errorMessage = 'No valid records found in CSV';
   354→          this.log.warn({ fileName, jobId }, 'CSV file contains no valid records');
   355→          return result;
   356→        }
   357→
   358→        // Process in batches
   359→        const batches = this.chunk(records, BATCH_SIZE);
   360→        const trainIdsUpdated = new Set<string>();
   361→
   362→        for (const batch of batches) {
   363→          const batchResult = await this.processBatch(batch, fileName, result);
   364→          for (const trainId of batchResult.trainIdsUpdated) {
   365→            trainIdsUpdated.add(trainId);
   366→          }
   367→        }
   368→
   369→        result.trainsUpdated = trainIdsUpdated.size;
   370→
   371→        // Update train current mileage for all affected trains
   372→        await this.updateTrainMileage(records, trainIdsUpdated);
   373→
   374→        // Determine final status
   375→        if (result.invalidRecords > 0 && result.validRecords > 0) {
   376→          result.status = 'PARTIAL';
   377→        } else if (result.validRecords === 0) {
   378→          result.status = 'FAILED';
   379→          result.errorMessage = 'All records failed validation';
   380→        }
   381→
   382→        result.processingTimeMs = Date.now() - startTime;
   383→
   384→        span.setAttribute('result.validRecords', result.validRecords);
   385→        span.setAttribute('result.invalidRecords', result.invalidRecords);
   386→        span.setAttribute('result.anomalyCount', result.anomalies.length);
   387→        span.setAttribute('result.status', result.status);
   388→
   389→        recordIngestionComplete(result.status, result.processingTimeMs);
   390→
   391→        this.log.info(
   392→          {
   393→            jobId,
   394→            fileName,
   395→            totalRecords: result.totalRecords,
   396→            validRecords: result.validRecords,
   397→            invalidRecords: result.invalidRecords,
   398→            anomalies: result.anomalies.length,
   399→            trainsUpdated: result.trainsUpdated,
   400→            processingTimeMs: result.processingTimeMs,
   401→            status: result.status,
   402→          },
   403→          `Ingestion complete: ${result.validRecords}/${result.totalRecords} records processed`
   404→        );
   405→
   406→        return result;
   407→      } catch (error) {
   408→        result.processingTimeMs = Date.now() - startTime;
   409→        result.status = 'FAILED';
   410→        result.errorMessage = error instanceof Error ? error.message : 'Unknown error';
   411→
   412→        recordIngestionComplete('FAILED', result.processingTimeMs);
   413→
   414→        this.log.error(
   415→          { error, jobId, fileName },
   416→          `Ingestion failed: ${result.errorMessage}`
   417→        );
   418→
   419→        throw error;
   420→      }
   421→    });
   422→  }
