  1519→  // ===========================================================================
  1520→  // Tactical Scheduling Run
  1521→  // ===========================================================================
  1522→
  1523→  /**
  1524→   * Run tactical scheduling for the 12-week horizon.
  1525→   *
  1526→   * This method:
  1527→   * 1. Calculates PM due dates for all trains in scope
  1528→   * 2. Prioritizes by overdue status and due date
  1529→   * 3. Attempts to schedule each PM respecting constraints
  1530→   * 4. Returns a detailed result with scheduled, deferred, and blocked PMs
  1531→   */
  1532→  async runTacticalSchedule(request: TacticalScheduleRequest): Promise<SchedulingResult> {
  1533→    return this.traced('runTacticalSchedule', async (span) => {
  1534→      const {
  1535→        fleetId,
  1536→        depotId,
  1537→        horizonWeeks = DEFAULT_HORIZON_WEEKS,
  1538→        dryRun = false,
  1539→        respectLocks = true,
  1540→      } = request;
  1541→
  1542→      span.setAttribute('schedule.horizonWeeks', horizonWeeks);
  1543→      span.setAttribute('schedule.dryRun', dryRun);
  1544→
  1545→      const today = new Date();
  1546→      const horizonStart = today.toISOString().split('T')[0];
  1547→      const horizonEnd = new Date(today.getTime() + horizonWeeks * 7 * 24 * 60 * 60 * 1000)
  1548→        .toISOString()
  1549→        .split('T')[0];
  1550→
  1551→      // Get trains in scope
  1552→      const trainConditions: SQL<unknown>[] = [
  1553→        eq(trains.active, true),
  1554→        eq(trains.fitnessStatus, 'FIT'),
  1555→      ];
  1556→
  1557→      if (fleetId) {
  1558→        trainConditions.push(eq(trains.fleetId, fleetId));
  1559→      }
  1560→      if (depotId) {
  1561→        trainConditions.push(eq(trains.currentDepotId, depotId));
  1562→      }
  1563→
  1564→      const trainsInScope = await this.db.query.trains.findMany({
  1565→        where: and(...trainConditions),
  1566→        with: { fleet: true },
  1567→      });
  1568→
  1569→      span.setAttribute('schedule.trainsInScope', trainsInScope.length);
  1570→
  1571→      // Calculate PM due for all trains
  1572→      const allDueResults: PmDueResult[] = [];
  1573→
  1574→      for (const train of trainsInScope) {
  1575→        const dueResults = await this.calculateAllPmDue(train.id);
  1576→        allDueResults.push(...dueResults);
  1577→      }
  1578→
  1579→      // Filter to PMs due within horizon
  1580→      const pmsDueInHorizon = allDueResults.filter(pm =>
  1581→        pm.complianceWindow.startDate <= horizonEnd &&
  1582→        pm.complianceWindow.endDate >= horizonStart
  1583→      );
  1584→
  1585→      // Sort by priority (overdue first, then by due date)
  1586→      pmsDueInHorizon.sort((a, b) => {
  1587→        if (a.isOverdue && !b.isOverdue) return -1;
  1588→        if (!a.isOverdue && b.isOverdue) return 1;
  1589→        return a.complianceWindow.idealDate.localeCompare(b.complianceWindow.idealDate);
  1590→      });
  1591→
  1592→      span.setAttribute('schedule.pmsDueInHorizon', pmsDueInHorizon.length);
  1593→
  1594→      // Process each PM
  1595→      const scheduled: SchedulingResultItem[] = [];
  1596→      const deferred: SchedulingResultItem[] = [];
  1597→      const blocked: SchedulingResultItem[] = [];
  1598→      const materialWarnings: SchedulingResult['materialWarnings'] = [];
  1599→
  1600→      for (const pmDue of pmsDueInHorizon) {
  1601→        // Check if already scheduled
  1602→        const existingPm = await this.db.query.pmSchedule.findFirst({
  1603→          where: and(
  1604→            eq(pmSchedule.trainId, pmDue.trainId),
  1605→            eq(pmSchedule.pmTypeId, pmDue.pmTypeId),
  1606→            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  1607→            isNull(pmSchedule.scenarioId),
  1608→            gte(pmSchedule.targetDate, horizonStart),
  1609→            lte(pmSchedule.targetDate, horizonEnd)
  1610→          ),
  1611→        });
  1612→
  1613→        if (existingPm) {
  1614→          // Skip if locked and we're respecting locks
  1615→          if (respectLocks && existingPm.isLocked) {
  1616→            continue;
  1617→          }
  1618→        }
  1619→
  1620→        // Try to schedule
  1621→        const result = await this.attemptSchedulePm(pmDue, horizonEnd, dryRun);
  1622→
  1623→        if (result.status === 'SCHEDULED') {
  1624→          scheduled.push(result);
  1625→
  1626→          if (result.materialConstraint?.softConstraintWarnings.length) {
  1627→            materialWarnings.push({
  1628→              trainId: pmDue.trainId,
  1629→              trainNumber: pmDue.trainNumber,
  1630→              pmCode: pmDue.pmCode,
  1631→              targetDate: result.targetDate!,
  1632→              warnings: result.materialConstraint.softConstraintWarnings,
  1633→            });
  1634→          }
  1635→        } else if (result.status === 'DEFERRED') {
  1636→          deferred.push(result);
  1637→        } else {
  1638→          blocked.push(result);
  1639→        }
  1640→      }
  1641→
  1642→      // Calculate track utilization
  1643→      const trackUtilization = await this.calculateTrackUtilization(
  1644→        horizonStart,
  1645→        horizonEnd,
  1646→        depotId ?? null
  1647→      );
  1648→
  1649→      const summary = {
  1650→        totalProcessed: pmsDueInHorizon.length,
  1651→        totalScheduled: scheduled.length,
  1652→        totalDeferred: deferred.length,
  1653→        totalBlocked: blocked.length,
  1654→        trackUtilizationPct: trackUtilization,
  1655→      };
  1656→
  1657→      span.setAttribute('result.scheduled', scheduled.length);
  1658→      span.setAttribute('result.deferred', deferred.length);
  1659→      span.setAttribute('result.blocked', blocked.length);
  1660→      span.setAttribute('result.trackUtilization', trackUtilization);
  1661→
  1662→      this.log.info(
  1663→        {
  1664→          horizonStart,
  1665→          horizonEnd,
  1666→          ...summary,
  1667→          fleetId,
  1668→          depotId,
  1669→        },
  1670→        `Tactical scheduling complete: ${scheduled.length} scheduled, ${deferred.length} deferred, ${blocked.length} blocked`
  1671→      );
  1672→
  1673→      return {
  1674→        horizonStart,
  1675→        horizonEnd,
  1676→        scheduled,
  1677→        deferred,
  1678→        blocked,
  1679→        materialWarnings,
  1680→        summary,
  1681→      };
  1682→    });
  1683→  }
  1684→
  1685→  /**
  1686→   * Attempt to schedule a single PM within constraints.
  1687→   */
  1688→  private async attemptSchedulePm(
  1689→    pmDue: PmDueResult,
  1690→    horizonEnd: string,
  1691→    dryRun: boolean
  1692→  ): Promise<SchedulingResultItem> {
  1693→    const explanation: SchedulingExplanation = {
  1694→      mileageTrigger: {
  1695→        intervalKm: null,
  1696→        currentMileageKm: pmDue.currentMileageKm,
  1697→        lastPmMileageKm: pmDue.lastPmMileageKm,
  1698→        kmSinceLastPm: pmDue.lastPmMileageKm !== null
  1699→          ? pmDue.currentMileageKm - pmDue.lastPmMileageKm
  1700→          : null,
  1701→        kmUntilDue: pmDue.kmUntilDue,
  1702→      },
  1703→      timeTrigger: {
  1704→        intervalMonths: null,
  1705→        lastPmDate: pmDue.lastPmDate,
  1706→        daysSinceLastPm: pmDue.lastPmDate
  1707→          ? Math.floor((Date.now() - new Date(pmDue.lastPmDate).getTime()) / (1000 * 60 * 60 * 24))
  1708→          : null,
  1709→        daysUntilDue: pmDue.daysUntilDue,
  1710→      },
  1711→      hierarchySatisfied: {
  1712→        satisfiedBy: null,
  1713→        satisfiedOnDate: null,
  1714→        counterResetFrom: null,
  1715→      },
  1716→      trackSelection: {
  1717→        candidateTracks: 0,
  1718→        selectedTrackId: null,
  1719→        selectionReason: '',
  1720→      },
  1721→      materialCheck: {
  1722→        totalParts: 0,
  1723→        availableParts: 0,
  1724→        blockedParts: 0,
  1725→        warningParts: 0,
  1726→      },
  1727→      constraints: [],
  1728→    };
  1729→
  1730→    const warnings: string[] = [];
  1731→
  1732→    // Check unavailability
  1733→    const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(pmDue.trainId);
  1734→    const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);
  1735→
  1736→    if (blockingEvent) {
  1737→      explanation.constraints.push(`Blocked by unavailability: ${blockingEvent.eventType}`);
  1738→
  1739→      return {
  1740→        trainId: pmDue.trainId,
  1741→        trainNumber: pmDue.trainNumber,
  1742→        pmTypeId: pmDue.pmTypeId,
  1743→        pmCode: pmDue.pmCode,
  1744→        status: 'BLOCKED',
  1745→        targetDate: null,
  1746→        targetMileageKm: null,
  1747→        trackAllocation: null,
  1748→        materialConstraint: null,
  1749→        complianceWindow: pmDue.complianceWindow,
  1750→        deferralReason: `Train has active unavailability: ${blockingEvent.eventType}`,
  1751→        warnings,
  1752→        explanation,
  1753→      };
  1754→    }
  1755→
  1756→    // Determine ideal target date (within horizon)
  1757→    let targetDate = pmDue.complianceWindow.idealDate;
  1758→    if (targetDate > horizonEnd) {
  1759→      targetDate = horizonEnd;
  1760→    }
  1761→    if (targetDate < new Date().toISOString().split('T')[0]) {
  1762→      targetDate = new Date().toISOString().split('T')[0];
  1763→    }
  1764→
  1765→    // Check service demand
  1766→    const demandCheck = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1767→      pmDue.trainId,
  1768→      targetDate
  1769→    );
  1770→
  1771→    if (!demandCheck.canSchedule) {
  1772→      // Try alternative dates within compliance window
  1773→      const alternativeDate = await this.findAlternativeDateForServiceDemand(
  1774→        pmDue.trainId,
  1775→        pmDue.complianceWindow.startDate,
  1776→        pmDue.complianceWindow.endDate
  1777→      );
  1778→
  1779→      if (!alternativeDate) {
  1780→        explanation.constraints.push(`Service demand violation: ${demandCheck.validation.message}`);
  1781→
  1782→        return {
  1783→          trainId: pmDue.trainId,
  1784→          trainNumber: pmDue.trainNumber,
  1785→          pmTypeId: pmDue.pmTypeId,
  1786→          pmCode: pmDue.pmCode,
  1787→          status: 'DEFERRED',
  1788→          targetDate: null,
  1789→          targetMileageKm: null,
  1790→          trackAllocation: null,
  1791→          materialConstraint: null,
  1792→          complianceWindow: pmDue.complianceWindow,
  1793→          deferralReason: demandCheck.validation.message,
  1794→          warnings,
  1795→          explanation,
  1796→        };
  1797→      }
  1798→
  1799→      targetDate = alternativeDate;
  1800→      warnings.push(`Rescheduled to ${alternativeDate} due to service demand constraints`);
  1801→    }
  1802→
  1803→    // Get train's depot
  1804→    const train = await this.db.query.trains.findFirst({
  1805→      where: eq(trains.id, pmDue.trainId),
  1806→    });
  1807→
  1808→    const depotId = train?.currentDepotId ?? train?.homeDepotId;
  1809→    if (!depotId) {
  1810→      explanation.constraints.push('No depot available for train');
  1811→
  1812→      return {
  1813→        trainId: pmDue.trainId,
  1814→        trainNumber: pmDue.trainNumber,
  1815→        pmTypeId: pmDue.pmTypeId,
  1816→        pmCode: pmDue.pmCode,
  1817→        status: 'BLOCKED',
  1818→        targetDate: null,
  1819→        targetMileageKm: null,
  1820→        trackAllocation: null,
  1821→        materialConstraint: null,
  1822→        complianceWindow: pmDue.complianceWindow,
  1823→        deferralReason: 'Train has no assigned depot',
  1824→        warnings,
  1825→        explanation,
  1826→      };
  1827→    }
  1828→
  1829→    // Get PM type for track duration
  1830→    const pmType = await this.db.query.pmTypes.findFirst({
  1831→      where: eq(pmTypes.id, pmDue.pmTypeId),
  1832→    });
  1833→
  1834→    const trackDuration = pmType?.minTrackDays ?? 1;
  1835→
  1836→    // Find suitable tracks
  1837→    const suitableTracks = await this.findSuitableTracks(
  1838→      pmDue.pmTypeId,
  1839→      depotId,
  1840→      targetDate,
  1841→      trackDuration
  1842→    );
  1843→
  1844→    explanation.trackSelection.candidateTracks = suitableTracks.length;
  1845→
  1846→    if (suitableTracks.length === 0) {
  1847→      explanation.constraints.push('No suitable tracks available');
  1848→      explanation.trackSelection.selectionReason = 'No tracks match requirements or all are occupied';
  1849→
  1850→      return {
  1851→        trainId: pmDue.trainId,
  1852→        trainNumber: pmDue.trainNumber,
  1853→        pmTypeId: pmDue.pmTypeId,
  1854→        pmCode: pmDue.pmCode,
  1855→        status: 'DEFERRED',
  1856→        targetDate: null,
  1857→        targetMileageKm: null,
  1858→        trackAllocation: null,
  1859→        materialConstraint: null,
  1860→        complianceWindow: pmDue.complianceWindow,
  1861→        deferralReason: 'No suitable tracks available',
  1862→        warnings,
  1863→        explanation,
  1864→      };
  1865→    }
  1866→
  1867→    const selectedTrack = suitableTracks[0];
  1868→    explanation.trackSelection.selectedTrackId = selectedTrack.trackId;
  1869→    explanation.trackSelection.selectionReason = selectedTrack.hasAllCapabilities
  1870→      ? 'Track has all required capabilities'
  1871→      : `Track missing: ${selectedTrack.missingCapabilities.join(', ')}`;
  1872→
  1873→    if (!selectedTrack.hasAllCapabilities) {
  1874→      warnings.push(`Selected track missing capabilities: ${selectedTrack.missingCapabilities.join(', ')}`);
  1875→    }
  1876→
  1877→    // Check material availability
  1878→    const materialResult = await this.checkMaterialAvailability(
  1879→      pmDue.pmTypeId,
  1880→      depotId,
  1881→      targetDate
  1882→    );
  1883→
  1884→    explanation.materialCheck.totalParts = materialResult.reservations.length +
  1885→      materialResult.hardConstraintViolations.length +
  1886→      materialResult.softConstraintWarnings.length;
  1887→    explanation.materialCheck.availableParts = materialResult.reservations.length;
  1888→    explanation.materialCheck.blockedParts = materialResult.hardConstraintViolations.length;
  1889→    explanation.materialCheck.warningParts = materialResult.softConstraintWarnings.length;
  1890→
  1891→    if (materialResult.isBlocked) {
  1892→      const blockingParts = materialResult.hardConstraintViolations
  1893→        .map(v => v.partNumber)
  1894→        .join(', ');
  1895→
  1896→      explanation.constraints.push(`Blocked by material constraint: ${blockingParts}`);
  1897→
  1898→      return {
  1899→        trainId: pmDue.trainId,
  1900→        trainNumber: pmDue.trainNumber,
  1901→        pmTypeId: pmDue.pmTypeId,
  1902→        pmCode: pmDue.pmCode,
  1903→        status: 'BLOCKED',
  1904→        targetDate: null,
  1905→        targetMileageKm: null,
  1906→        trackAllocation: selectedTrack,
  1907→        materialConstraint: materialResult,
  1908→        complianceWindow: pmDue.complianceWindow,
  1909→        deferralReason: `Blocking materials not available: ${blockingParts}`,
  1910→        warnings,
  1911→        explanation,
  1912→      };
  1913→    }
  1914→
  1915→    if (materialResult.softConstraintWarnings.length > 0) {
  1916→      const warningParts = materialResult.softConstraintWarnings
  1917→        .map(w => w.partNumber)
  1918→        .join(', ');
  1919→      warnings.push(`Material warning: ${warningParts} may not be available`);
  1920→    }
  1921→
  1922→    // Calculate target mileage
  1923→    const dailyKm = await this.getAverageDailyKm(pmDue.trainId);
  1924→    const daysUntilTarget = Math.ceil(
  1925→      (new Date(targetDate).getTime() - Date.now()) / (1000 * 60 * 60 * 24)
  1926→    );
  1927→    const targetMileageKm = pmDue.currentMileageKm + (daysUntilTarget * dailyKm);
  1928→
  1929→    // Create the PM schedule if not dry run
  1930→    if (!dryRun) {
  1931→      try {
  1932→        await this.schedulePm({
  1933→          trainId: pmDue.trainId,
  1934→          pmTypeId: pmDue.pmTypeId,
  1935→          targetDate,
  1936→          assignedDepotId: depotId,
  1937→          assignedTrackId: selectedTrack.trackId,
  1938→          skipMaterialCheck: true, // Already checked
  1939→          skipServiceDemandCheck: true, // Already checked
  1940→        });
  1941→      } catch (error) {
  1942→        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
  1943→        explanation.constraints.push(`Scheduling failed: ${errorMessage}`);
  1944→
  1945→        return {
  1946→          trainId: pmDue.trainId,
  1947→          trainNumber: pmDue.trainNumber,
  1948→          pmTypeId: pmDue.pmTypeId,
  1949→          pmCode: pmDue.pmCode,
  1950→          status: 'BLOCKED',
  1951→          targetDate: null,
  1952→          targetMileageKm: null,
  1953→          trackAllocation: selectedTrack,
  1954→          materialConstraint: materialResult,
  1955→          complianceWindow: pmDue.complianceWindow,
  1956→          deferralReason: errorMessage,
  1957→          warnings,
  1958→          explanation,
  1959→        };
  1960→      }
  1961→    }
  1962→
  1963→    return {
  1964→      trainId: pmDue.trainId,
  1965→      trainNumber: pmDue.trainNumber,
  1966→      pmTypeId: pmDue.pmTypeId,
  1967→      pmCode: pmDue.pmCode,
  1968→      status: 'SCHEDULED',
  1969→      targetDate,
  1970→      targetMileageKm: Math.round(targetMileageKm),
  1971→      trackAllocation: selectedTrack,
  1972→      materialConstraint: materialResult,
  1973→      complianceWindow: pmDue.complianceWindow,
  1974→      deferralReason: null,
  1975→      warnings,
  1976→      explanation,
  1977→    };
  1978→  }
  1979→
  1980→  // ===========================================================================
  1981→  // Query Methods
  1982→  // ===========================================================================
  1983→
  1984→  /**
  1985→   * Get PM schedule by ID with full details.
  1986→   */
  1987→  async getPm(pmScheduleId: string): Promise<PmWithDetails> {
  1988→    return this.traced('getPm', async (span) => {
  1989→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1990→
  1991→      const pm = await this.db.query.pmSchedule.findFirst({
  1992→        where: eq(pmSchedule.id, pmScheduleId),
  1993→        with: {
  1994→          train: true,
  1995→          pmType: true,
  1996→          assignedTrack: true,
  1997→          assignedDepot: true,
  1998→        },
  1999→      });
  2000→
  2001→      if (!pm) {
  2002→        throw new PmScheduleNotFoundError(pmScheduleId);
  2003→      }
  2004→
  2005→      return pm as PmWithDetails;
  2006→    });
  2007→  }
  2008→
  2009→  /**
  2010→   * Get PM history.
  2011→   */
  2012→  async getPmHistory(pmScheduleId: string) {
  2013→    return this.traced('getPmHistory', async (span) => {
  2014→      span.setAttribute('pm.scheduleId', pmScheduleId);
  2015→
  2016→      const history = await this.db.query.pmScheduleHistory.findMany({
  2017→        where: eq(pmScheduleHistory.pmScheduleId, pmScheduleId),
  2018→        orderBy: desc(pmScheduleHistory.changedAt),
  2019→        with: {
  2020→          changedByUser: true,
  2021→        },
  2022→      });
  2023→
  2024→      return history;
  2025→    });
  2026→  }
  2027→
  2028→  // ===========================================================================
  2029→  // Helper Methods
  2030→  // ===========================================================================
  2031→
  2032→  /**
  2033→   * Get last completed PM of a type for a train.
  2034→   */
  2035→  private async getLastCompletedPm(
  2036→    trainId: string,
  2037→    pmTypeId: string
  2038→  ): Promise<PmScheduleRecord | null> {
  2039→    const lastPm = await this.db.query.pmSchedule.findFirst({
  2040→      where: and(
  2041→        eq(pmSchedule.trainId, trainId),
  2042→        eq(pmSchedule.pmTypeId, pmTypeId),
  2043→        eq(pmSchedule.status, 'COMPLETED'),
  2044→        isNull(pmSchedule.scenarioId)
  2045→      ),
  2046→      orderBy: desc(pmSchedule.completedAt),
  2047→    });
  2048→
  2049→    return lastPm ?? null;
  2050→  }
  2051→
  2052→  /**
  2053→   * Get average daily km for a train from recent mileage readings.
  2054→   */
  2055→  private async getAverageDailyKm(trainId: string): Promise<number> {
  2056→    const thirtyDaysAgo = new Date();
  2057→    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  2058→
  2059→    const readings = await this.db
  2060→      .select({
  2061→        avgDailyKm: sql<number>`AVG(${mileageReadings.dailyKm})`,
  2062→      })
  2063→      .from(mileageReadings)
  2064→      .where(
  2065→        and(
  2066→          eq(mileageReadings.trainId, trainId),
  2067→          gte(mileageReadings.readingDate, thirtyDaysAgo.toISOString().split('T')[0]),
  2068→          eq(mileageReadings.validationStatus, 'VALID')
  2069→        )
  2070→      );
  2071→
  2072→    return readings[0]?.avgDailyKm ?? DEFAULT_DAILY_KM;
  2073→  }
  2074→
  2075→  /**
  2076→   * Find an alternative date for scheduling when service demand blocks the ideal date.
  2077→   */
  2078→  private async findAlternativeDateForServiceDemand(
  2079→    trainId: string,
  2080→    windowStart: string,
  2081→    windowEnd: string
  2082→  ): Promise<string | null> {
  2083→    const start = new Date(windowStart);
  2084→    const end = new Date(windowEnd);
  2085→
  2086→    // Try each day in the window
  2087→    for (let d = start; d <= end; d.setDate(d.getDate() + 1)) {
  2088→      const dateStr = d.toISOString().split('T')[0];
  2089→      const { canSchedule } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  2090→        trainId,
  2091→        dateStr
  2092→      );
  2093→
  2094→      if (canSchedule) {
  2095→        return dateStr;
  2096→      }
  2097→    }
  2098→
  2099→    return null;
  2100→  }
  2101→
  2102→  /**
  2103→   * Calculate track utilization percentage for a period.
  2104→   */
  2105→  private async calculateTrackUtilization(
  2106→    startDate: string,
  2107→    endDate: string,
  2108→    depotId: string | null
  2109→  ): Promise<number> {
  2110→    // Get total track-days available
  2111→    const trackConditions: SQL<unknown>[] = [
  2112→      eq(tracks.active, true),
  2113→      sql`${tracks.trackType} != 'STABLING'`,
  2114→    ];
  2115→
  2116→    if (depotId) {
  2117→      trackConditions.push(eq(tracks.depotId, depotId));
  2118→    }
  2119→
  2120→    const trackCount = await this.db
  2121→      .select({ count: count() })
  2122→      .from(tracks)
  2123→      .where(and(...trackConditions));
  2124→
  2125→    const totalTracks = trackCount[0]?.count ?? 0;
  2126→    const daysBetween = Math.ceil(
  2127→      (new Date(endDate).getTime() - new Date(startDate).getTime()) / (1000 * 60 * 60 * 24)
  2128→    );
  2129→    const totalTrackDays = totalTracks * daysBetween;
  2130→
  2131→    if (totalTrackDays === 0) return 0;
  2132→
  2133→    // Get scheduled PM track-days
  2134→    const pmConditions: SQL<unknown>[] = [
  2135→      inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  2136→      isNull(pmSchedule.scenarioId),
  2137→      gte(pmSchedule.targetDate, startDate),
  2138→      lte(pmSchedule.targetDate, endDate),
  2139→      sql`${pmSchedule.assignedTrackId} IS NOT NULL`,
  2140→    ];
  2141→
  2142→    if (depotId) {
  2143→      pmConditions.push(eq(pmSchedule.assignedDepotId, depotId));
  2144→    }
  2145→
  2146→    const scheduledPms = await this.db.query.pmSchedule.findMany({
  2147→      where: and(...pmConditions),
  2148→      with: { pmType: true },
  2149→    });
  2150→
  2151→    const usedTrackDays = scheduledPms.reduce((sum, pm) => {
  2152→      const duration = pm.pmType?.minTrackDays ?? 1;
  2153→      return sum + duration;
  2154→    }, 0);
  2155→
  2156→    return Math.round((usedTrackDays / totalTrackDays) * 100);
  2157→  }
  2158→}
  2159→
  2160→// =============================================================================
  2161→// Singleton Export
  2162→// =============================================================================
  2163→
  2164→let pmSchedulerServiceInstance: PMSchedulerService | null = null;
  2165→
  2166→export function getPMSchedulerService(): PMSchedulerService {
  2167→  if (!pmSchedulerServiceInstance) {
  2168→    pmSchedulerServiceInstance = new PMSchedulerService();
  2169→  }
  2170→  return pmSchedulerServiceInstance;
  2171→}
  2172→
  2173→export default PMSchedulerService;
  2174→

